class GameChoice { const GameChoice({required this.number, required this.text}); final int number; final String text; factory GameChoice.fromJson(Map<String, dynamic> value) => GameChoice(number: value['number'] as int, text: value['text'] as String); }
class GameLevel { const GameLevel({required this.number, required this.narrative, required this.choices}); final int number; final String narrative; final List<GameChoice> choices; factory GameLevel.fromJson(Map<String, dynamic> value) => GameLevel(number: value['number'] as int, narrative: value['narrative'] as String, choices: (value['choices'] as List).map((entry) => GameChoice.fromJson(Map<String, dynamic>.from(entry as Map))).toList()); }
class Game { const Game({required this.id, required this.status, required this.stake, required this.score, required this.remaining, required this.title, required this.category, this.level, this.outcome}); final String id; final String status; final int stake; final int score; final int remaining; final String title; final String category; final GameLevel? level; final String? outcome;
  factory Game.fromJson(Map<String, dynamic> value) { final story = Map<String, dynamic>.from(value['story'] as Map); return Game(id: value['id'] as String, status: value['status'] as String, stake: value['stake'] as int, score: value['score'] as int, remaining: value['timeRemainingSeconds'] as int? ?? 0, title: story['title'] as String, category: story['category'] as String, level: value['level'] == null ? null : GameLevel.fromJson(Map<String, dynamic>.from(value['level'] as Map)), outcome: value['outcome'] as String?); }
}

